const MobileGeo=(()=>{const TAG='[MOBILE-GEO]';let isTracking=false;let authToken=null;let currentIntervention=null;let trackingStatus=null;function init(){console.log(`${TAG}Initializing mobile geolocation integration...`);if(!window.SofatelcomGeo){console.warn(`${TAG}SofatelcomGeo interface not available(not in Flutter)`);return false;}authToken=document.body.dataset.authToken||window.SOFATELCOM_AUTH_TOKEN||localStorage.getItem('access_token');if(!authToken){console.error(`${TAG}No auth token found. Cannot initialize GPS tracking.`);return false;}window.SofatelcomGeo.setAuthToken(authToken);currentIntervention=document.body.dataset.interventionId||window.CURRENT_INTERVENTION_ID||null;window.onGeoLocationUpdate=(latitude,longitude,accuracy)=>{console.log(`${TAG}Position:${latitude.toFixed(4)},${longitude.toFixed(4)}(±${accuracy.toFixed(1)}m)`);updateDashboardMap(latitude,longitude,accuracy);};window.onTrackingStatusChanged=(status)=>{isTracking=status==='active';console.log(`${TAG}Tracking status:${status}`);updateTrackingUI(isTracking);};console.log(`${TAG}Initialization complete`);return true;}function startTracking(){console.log(`${TAG}Starting GPS tracking...`);if(!window.SofatelcomGeo){console.warn(`${TAG}SofatelcomGeo not available`);return false;}try{window.SofatelcomGeo.startTracking();isTracking=true;updateTrackingUI(true);return true;}catch(e){console.error(`${TAG}Error starting tracking:`,e);return false;}}function stopTracking(){console.log(`${TAG}Stopping GPS tracking...`);if(!window.SofatelcomGeo){console.warn(`${TAG}SofatelcomGeo not available`);return false;}try{window.SofatelcomGeo.stopTracking();isTracking=false;updateTrackingUI(false);return true;}catch(e){console.error(`${TAG}Error stopping tracking:`,e);return false;}}function updateDashboardMap(latitude,longitude,accuracy){if(window.MapTracker&&window.MapTracker.state.map){const technicianId=document.body.dataset.technicianId||window.CURRENT_USER_ID;if(technicianId){const position={technicien_id:technicianId,latitude:latitude,longitude:longitude,accuracy:accuracy,timestamp:new Date().toISOString(),status:document.body.dataset.trackingStatus||'en_route'};MapTracker.updatePosition(position);}}const indicator=document.querySelector('[data-tracking-status]');if(indicator){indicator.textContent=`📍 ${latitude.toFixed(4)},${longitude.toFixed(4)}`;indicator.dataset.lastUpdate=new Date().toLocaleTimeString();}}function updateTrackingUI(active){const startBtn=document.querySelector('[data-action="start-tracking"]');const stopBtn=document.querySelector('[data-action="stop-tracking"]');if(startBtn){startBtn.disabled=active;startBtn.style.opacity=active ? '0.5':'1';}if(stopBtn){stopBtn.disabled=!active;stopBtn.style.opacity=active ? '1':'0.5';}const badge=document.querySelector('[data-tracking-badge]');if(badge){badge.textContent=active ? '🔴 ACTIF':'⏹️ INACTIF';badge.style.color=active ? '#dc3545':'#6c757d';}document.body.dataset.tracking=active ? 'true':'false';}function getStatus(){return{isTracking:isTracking,hasAuth:!!authToken,currentIntervention:currentIntervention,isAvailable:!!window.SofatelcomGeo};}function setCurrentIntervention(interventionId){currentIntervention=interventionId;console.log(`${TAG}Current intervention set to:${interventionId}`);}function toggle(){if(isTracking){return stopTracking();}else{return startTracking();}}return{init,startTracking,stopTracking,toggle,getStatus,setCurrentIntervention,isAvailable:()=>!!window.SofatelcomGeo,};})();document.addEventListener('DOMContentLoaded',()=>{setTimeout(()=>{MobileGeo.init();const startBtn=document.querySelector('[data-action="start-tracking"]');const stopBtn=document.querySelector('[data-action="stop-tracking"]');const toggleBtn=document.querySelector('[data-action="toggle-tracking"]');if(startBtn){startBtn.addEventListener('click',()=>MobileGeo.startTracking());}if(stopBtn){stopBtn.addEventListener('click',()=>MobileGeo.stopTracking());}if(toggleBtn){toggleBtn.addEventListener('click',()=>MobileGeo.toggle());}console.log('[MOBILE-GEO] Initialization listeners set up');},500);});window.MobileGeo=MobileGeo;